import fetch from "node-fetch";

export interface ShopifyPage {
  id: number;
  title: string;
  body_html: string;
  handle: string;
  template_suffix?: string;
  metafield?: {
    key: string;
    value: string;
    namespace: string;
  }[];
  created_at: string;
  updated_at: string;
}

export interface ShopifyProduct {
  id: number;
  title: string;
  body_html: string;
  handle: string;
  product_type: string;
  vendor: string;
  tags: string;
}

export interface CopyField {
  field: string;
  content: string;
  type: "text" | "html" | "meta";
}

export class ShopifyClient {
  private baseUrl: string;
  private headers: Record<string, string>;

  constructor(storeUrl: string, accessToken: string) {
    // Remove protocol and trailing slash if present
    const cleanUrl = storeUrl.replace(/^https?:\/\//, "").replace(/\/$/, "");
    this.baseUrl = `https://${cleanUrl}/admin/api/2024-01`;

    this.headers = {
      "X-Shopify-Access-Token": accessToken,
      "Content-Type": "application/json",
    };
  }

  // Page operations
  async getPage(pageId: string): Promise<ShopifyPage> {
    const response = await fetch(`${this.baseUrl}/pages/${pageId}.json`, {
      headers: this.headers,
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch page: ${response.statusText}`);
    }

    const data = await response.json() as { page: ShopifyPage };
    return data.page;
  }

  async listPages(): Promise<ShopifyPage[]> {
    const response = await fetch(`${this.baseUrl}/pages.json?limit=250`, {
      headers: this.headers,
    });

    if (!response.ok) {
      throw new Error(`Failed to list pages: ${response.statusText}`);
    }

    const data = await response.json() as { pages: ShopifyPage[] };
    return data.pages;
  }

  async updatePage(pageId: string, updates: Partial<ShopifyPage>): Promise<ShopifyPage> {
    const response = await fetch(`${this.baseUrl}/pages/${pageId}.json`, {
      method: "PUT",
      headers: this.headers,
      body: JSON.stringify({ page: updates }),
    });

    if (!response.ok) {
      throw new Error(`Failed to update page: ${response.statusText}`);
    }

    const data = await response.json() as { page: ShopifyPage };
    return data.page;
  }

  async createPage(title: string, content: string, templateSuffix?: string): Promise<ShopifyPage> {
    const response = await fetch(`${this.baseUrl}/pages.json`, {
      method: "POST",
      headers: this.headers,
      body: JSON.stringify({
        page: {
          title,
          body_html: content,
          template_suffix: templateSuffix,
          published: false, // Start as draft
        },
      }),
    });

    if (!response.ok) {
      throw new Error(`Failed to create page: ${response.statusText}`);
    }

    const data = await response.json() as { page: ShopifyPage };
    return data.page;
  }

  // Copy extraction utilities
  extractCopyFromPage(page: ShopifyPage): CopyField[] {
    const fields: CopyField[] = [
      {
        field: "title",
        content: page.title,
        type: "text",
      },
      {
        field: "content",
        content: this.stripHtml(page.body_html),
        type: "html",
      },
    ];

    // Add metafields if present
    if (page.metafield) {
      page.metafield.forEach((meta) => {
        if (meta.key.includes("description") || meta.key.includes("title")) {
          fields.push({
            field: `meta_${meta.key}`,
            content: meta.value,
            type: "meta",
          });
        }
      });
    }

    return fields;
  }

  private stripHtml(html: string): string {
    // Basic HTML stripping - in production, use a proper HTML parser
    return html
      .replace(/<[^>]*>/g, " ")
      .replace(/\s+/g, " ")
      .trim();
  }

  // Product operations
  async getProduct(productId: string): Promise<ShopifyProduct> {
    const response = await fetch(`${this.baseUrl}/products/${productId}.json`, {
      headers: this.headers,
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch product: ${response.statusText}`);
    }

    const data = await response.json() as { product: ShopifyProduct };
    return data.product;
  }

  async listProducts(limit = 50): Promise<ShopifyProduct[]> {
    const response = await fetch(`${this.baseUrl}/products.json?limit=${limit}`, {
      headers: this.headers,
    });

    if (!response.ok) {
      throw new Error(`Failed to list products: ${response.statusText}`);
    }

    const data = await response.json() as { products: ShopifyProduct[] };
    return data.products;
  }

  // Theme operations
  async getActiveTheme(): Promise<any> {
    const response = await fetch(`${this.baseUrl}/themes.json`, {
      headers: this.headers,
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch themes: ${response.statusText}`);
    }

    const data = await response.json() as { themes: any[] };
    return data.themes.find(theme => theme.role === "main");
  }

  async uploadAsset(themeId: string, key: string, value: string): Promise<any> {
    const response = await fetch(`${this.baseUrl}/themes/${themeId}/assets.json`, {
      method: "PUT",
      headers: this.headers,
      body: JSON.stringify({
        asset: {
          key,
          value,
        },
      }),
    });

    if (!response.ok) {
      throw new Error(`Failed to upload asset: ${response.statusText}`);
    }

    return response.json();
  }
}

