import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { CallToolRequestSchema, TextContent, ErrorContent } from "@modelcontextprotocol/sdk/types.js";
import { z } from "zod";
import { ShopifyClient } from "../lib/shopify-client.js";

// Tool schemas
const GetPageCopySchema = z.object({
  page_id: z.string().describe("The ID of the page to extract copy from"),
});

const UpdateCopyFieldSchema = z.object({
  page_id: z.string().describe("The ID of the page to update"),
  field: z.string().describe("The field to update (e.g., 'title', 'content', 'meta_description')"),
  content: z.string().describe("The new content for the field"),
});

const BulkUpdateCopySchema = z.object({
  search: z.string().describe("Text to search for"),
  replace: z.string().describe("Text to replace with"),
  page_ids: z.array(z.string()).optional().describe("Specific page IDs to update (optional, defaults to all pages)"),
});

export function registerCopyTools(server: Server, shopifyClient: ShopifyClient) {
  // Handle tool calls
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    try {
      switch (name) {
        case "get_page_copy": {
          const parsed = GetPageCopySchema.parse(args);
          const page = await shopifyClient.getPage(parsed.page_id);
          const copyFields = shopifyClient.extractCopyFromPage(page);

          const formattedCopy = copyFields
            .map(field => `[${field.field}]:\n${field.content}`)
            .join("\n\n");

          return {
            content: [
              {
                type: "text",
                text: formattedCopy,
              } as TextContent,
            ],
          };
        }

        case "update_copy_field": {
          const parsed = UpdateCopyFieldSchema.parse(args);

          // Map field names to Shopify API fields
          const fieldMap: Record<string, string> = {
            "title": "title",
            "content": "body_html",
            "body": "body_html",
            "description": "body_html",
          };

          const shopifyField = fieldMap[parsed.field] || parsed.field;

          // Prepare update object
          const updates: Record<string, any> = {
            [shopifyField]: parsed.content,
          };

          // If updating body_html and it's plain text, wrap in basic HTML
          if (shopifyField === "body_html" && !parsed.content.includes("<")) {
            updates.body_html = `<p>${parsed.content}</p>`;
          }

          const updatedPage = await shopifyClient.updatePage(parsed.page_id, updates);

          return {
            content: [
              {
                type: "text",
                text: `Successfully updated ${parsed.field} for page "${updatedPage.title}"`,
              } as TextContent,
            ],
          };
        }

        case "bulk_update_copy": {
          const parsed = BulkUpdateCopySchema.parse(args);

          // Get pages to update
          const pages = parsed.page_ids
            ? await Promise.all(parsed.page_ids.map(id => shopifyClient.getPage(id)))
            : await shopifyClient.listPages();

          let updatedCount = 0;
          const updates: string[] = [];

          for (const page of pages) {
            let updated = false;
            const newData: Record<string, any> = {};

            // Check and update title
            if (page.title.includes(parsed.search)) {
              newData.title = page.title.replace(new RegExp(parsed.search, "g"), parsed.replace);
              updated = true;
            }

            // Check and update body
            if (page.body_html.includes(parsed.search)) {
              newData.body_html = page.body_html.replace(new RegExp(parsed.search, "g"), parsed.replace);
              updated = true;
            }

            if (updated) {
              await shopifyClient.updatePage(page.id.toString(), newData);
              updatedCount++;
              updates.push(`- ${page.title} (ID: ${page.id})`);
            }
          }

          return {
            content: [
              {
                type: "text",
                text: `Bulk update complete:\n- Searched: "${parsed.search}"\n- Replaced with: "${parsed.replace}"\n- Pages updated: ${updatedCount}\n${updates.length > 0 ? "\nUpdated pages:\n" + updates.join("\n") : ""}`,
              } as TextContent,
            ],
          };
        }

        case "list_editable_pages": {
          const pages = await shopifyClient.listPages();

          const pageList = pages.map(page =>
            `- ${page.title} (ID: ${page.id}, Handle: ${page.handle})`
          ).join("\n");

          return {
            content: [
              {
                type: "text",
                text: `Found ${pages.length} editable pages:\n\n${pageList}`,
              } as TextContent,
            ],
          };
        }

        default:
          return {
            content: [
              {
                type: "text",
                text: `Unknown tool: ${name}`,
              } as ErrorContent,
            ],
            isError: true,
          };
      }
    } catch (error) {
      return {
        content: [
          {
            type: "text",
            text: `Error executing ${name}: ${error instanceof Error ? error.message : String(error)}`,
          } as ErrorContent,
        ],
        isError: true,
      };
    }
  });
}

