import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { CallToolRequestSchema, TextContent, ErrorContent } from "@modelcontextprotocol/sdk/types.js";
import { z } from "zod";
import { ShopifyClient } from "../lib/shopify-client.js";

// Tool schemas
const CreatePageSchema = z.object({
  title: z.string().describe("The title of the new page"),
  content: z.string().describe("The HTML content of the page"),
  template_suffix: z.string().optional().describe("Optional template suffix to use"),
});

const DeletePageSchema = z.object({
  page_id: z.string().describe("The ID of the page to delete"),
});

const DuplicatePageSchema = z.object({
  page_id: z.string().describe("The ID of the page to duplicate"),
  new_title: z.string().describe("Title for the duplicated page"),
});

export function registerPageTools(server: Server, shopifyClient: ShopifyClient) {
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    try {
      switch (name) {
        case "create_page": {
          const parsed = CreatePageSchema.parse(args);

          const newPage = await shopifyClient.createPage(
            parsed.title,
            parsed.content,
            parsed.template_suffix
          );

          return {
            content: [
              {
                type: "text",
                text: `Successfully created page "${newPage.title}"\nID: ${newPage.id}\nHandle: ${newPage.handle}\nStatus: Draft (unpublished)`,
              } as TextContent,
            ],
          };
        }

        case "duplicate_page": {
          const parsed = DuplicatePageSchema.parse(args);

          // Get original page
          const originalPage = await shopifyClient.getPage(parsed.page_id);

          // Create duplicate with new title
          const duplicatedPage = await shopifyClient.createPage(
            parsed.new_title,
            originalPage.body_html,
            originalPage.template_suffix
          );

          return {
            content: [
              {
                type: "text",
                text: `Successfully duplicated page\nOriginal: "${originalPage.title}" (ID: ${originalPage.id})\nDuplicate: "${duplicatedPage.title}" (ID: ${duplicatedPage.id})`,
              } as TextContent,
            ],
          };
        }

        default:
          // Let other tool handlers process if not our tool
          return null;
      }
    } catch (error) {
      if (["create_page", "duplicate_page"].includes(name)) {
        return {
          content: [
            {
              type: "text",
              text: `Error executing ${name}: ${error instanceof Error ? error.message : String(error)}`,
            } as ErrorContent,
          ],
          isError: true,
        };
      }
      // Not our tool, let other handlers process
      return null;
    }
  });
}

