import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { registerCopyTools } from "./tools/copyTools.js";
import { registerPageTools } from "./tools/pageTools.js";
import { registerThemeTools } from "./tools/themeTools.js";
import { ShopifyClient } from "./lib/shopify-client.js";
import dotenv from "dotenv";

// Load environment variables
dotenv.config();

// Validate required environment variables
const requiredEnvVars = ["SHOPIFY_STORE_URL", "SHOPIFY_ACCESS_TOKEN"];
for (const envVar of requiredEnvVars) {
  if (!process.env[envVar]) {
    console.error(`Error: ${envVar} environment variable is required`);
    process.exit(1);
  }
}

// Initialize Shopify client
const shopifyClient = new ShopifyClient(
  process.env.SHOPIFY_STORE_URL!,
  process.env.SHOPIFY_ACCESS_TOKEN!
);

// Create MCP server
const server = new Server(
  {
    name: "shopify-liquid-mcp",
    version: "0.1.0",
  },
  {
    capabilities: {
      tools: {},
    },
  }
);

// Register tool handlers
registerCopyTools(server, shopifyClient);
registerPageTools(server, shopifyClient);
registerThemeTools(server, shopifyClient);

// Handle tool listing
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      // Copy management tools
      {
        name: "get_page_copy",
        description: "Extract copy content from a Shopify page",
        inputSchema: {
          type: "object",
          properties: {
            page_id: {
              type: "string",
              description: "The ID of the page to extract copy from",
            },
          },
          required: ["page_id"],
        },
      },
      {
        name: "update_copy_field",
        description: "Update a specific text field on a page",
