import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { CallToolRequestSchema, TextContent, ErrorContent } from "@modelcontextprotocol/sdk/types.js";
import { z } from "zod";
import { LocalThemeClient } from "../lib/local-theme-client.js";

// Tool schemas
const ExtractAllCopySchema = z.object({});

const UpdateCopyFieldSchema = z.object({
  file: z.string().describe("The file path relative to theme root (e.g., 'templates/index.json')"),
  path: z.string().describe("JSON path to the field (e.g., 'sections.hero_banner.settings.title')"),
  value: z.string().describe("New value for the field"),
});

const BulkReplaceSchema = z.object({
  search: z.string().describe("Text to search for"),
  replace: z.string().describe("Text to replace with"),
});

const SearchCopySchema = z.object({
  query: z.string().describe("Search query to find in copy"),
});

export function registerLocalCopyTools(server: Server, themeClient: LocalThemeClient) {
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    try {
      switch (name) {
        case "extract_all_copy": {
          const copy = await themeClient.extractAllCopy();

          // Group by file for better readability
          const grouped: Record<string, any[]> = {};
          for (const field of copy) {
            if (!grouped[field.file]) grouped[field.file] = [];
            grouped[field.file].push(field);
          }

          let output = `Found ${copy.length} copy fields across ${Object.keys(grouped).length} files:\n\n`;

          for (const [file, fields] of Object.entries(grouped)) {
            output += `📁 ${file}:\n`;
            for (const field of fields) {
              const preview = field.value.length > 60
                ? field.value.substring(0, 60) + "..."
                : field.value;
              output += `  • ${field.field}: "${preview}"\n`;
            }
            output += "\n";
          }

          return {
            content: [
              {
                type: "text",
                text: output,
              } as TextContent,
            ],
          };
        }

        case "update_copy_field": {
          const parsed = UpdateCopyFieldSchema.parse(args);

          await themeClient.updateCopyField(parsed.file, parsed.path, parsed.value);

          return {
            content: [
              {
                type: "text",
                text: `✅ Updated ${parsed.path} in ${parsed.file}\nNew value: "${parsed.value}"`,
              } as TextContent,
            ],
          };
        }

        case "bulk_replace_copy": {
          const parsed = BulkReplaceSchema.parse(args);

          const count = await themeClient.bulkReplaceCopy(parsed.search, parsed.replace);

          return {
            content: [
              {
                type: "text",
                text: `✅ Bulk replace complete:\n• Searched for: "${parsed.search}"\n• Replaced with: "${parsed.replace}"\n• Updated ${count} fields`,
              } as TextContent,
            ],
          };
        }

        case "search_copy": {
          const parsed = SearchCopySchema.parse(args);
          const copy = await themeClient.extractAllCopy();

          const matches = copy.filter(field =>
            field.value.toLowerCase().includes(parsed.query.toLowerCase())
          );

          if (matches.length === 0) {
            return {
              content: [
                {
                  type: "text",
                  text: `No matches found for "${parsed.query}"`,
                } as TextContent,
              ],
            };
          }

          let output = `Found ${matches.length} matches for "${parsed.query}":\n\n`;
          for (const match of matches) {
            output += `📍 ${match.file} > ${match.path}:\n`;
            output += `   "${match.value}"\n\n`;
          }

          return {
            content: [
              {
                type: "text",
                text: output,
              } as TextContent,
            ],
          };
        }

        default:
          return null;
      }
    } catch (error) {
      if (["extract_all_copy", "update_copy_field", "bulk_replace_copy", "search_copy"].includes(name)) {
        return {
          content: [
            {
              type: "text",
              text: `❌ Error: ${error instanceof Error ? error.message : String(error)}`,
            } as ErrorContent,
          ],
          isError: true,
        };
      }
      return null;
    }
  });
}

