import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { CallToolRequestSchema, TextContent, ErrorContent } from "@modelcontextprotocol/sdk/types.js";
import { z } from "zod";
import { LocalThemeClient } from "../lib/local-theme-client.js";

// Tool schemas
const ListTemplatesSchema = z.object({});

const CreateTemplateSchema = z.object({
  name: z.string().describe("Template name (without extension)"),
  sections: z.array(z.object({
    type: z.string().describe("Section type (must exist in sections/)"),
    settings: z.record(z.any()).optional().describe("Section settings"),
  })).describe("Array of sections to include in template"),
});

export function registerLocalTemplateTools(server: Server, themeClient: LocalThemeClient) {
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    try {
      switch (name) {
        case "list_templates": {
          const templates = await themeClient.listTemplates();

          const jsonTemplates = templates.filter(t => t.endsWith(".json"));
          const liquidTemplates = templates.filter(t => t.endsWith(".liquid"));

          let output = `📂 Templates (${templates.length} total):\n\n`;

          if (jsonTemplates.length > 0) {
            output += "JSON Templates:\n";
            jsonTemplates.forEach(t => output += `  • ${t}\n`);
            output += "\n";
          }

          if (liquidTemplates.length > 0) {
            output += "Liquid Templates:\n";
            liquidTemplates.forEach(t => output += `  • ${t}\n`);
          }

          return {
            content: [
              {
                type: "text",
                text: output,
              } as TextContent,
            ],
          };
        }

        case "create_template": {
          const parsed = CreateTemplateSchema.parse(args);

          await themeClient.createTemplate(parsed.name, parsed.sections);

          return {
            content: [
              {
                type: "text",
                text: `✅ Created template: templates/${parsed.name}.json\nSections added: ${parsed.sections.map(s => s.type).join(", ")}`,
              } as TextContent,
            ],
          };
        }

        default:
          return null;
      }
    } catch (error) {
      if (["list_templates", "create_template"].includes(name)) {
        return {
          content: [
            {
              type: "text",
              text: `❌ Error: ${error instanceof Error ? error.message : String(error)}`,
            } as ErrorContent,
          ],
          isError: true,
        };
      }
      return null;
    }
  });
}

