import { CallToolRequestSchema, TextContent, ErrorContent } from "@modelcontextprotocol/sdk/types.js";
import { z } from "zod";
import { LocalThemeClient } from "../lib/local-theme-client.js";

// Tool schemas
const GitStatusSchema = z.object({});

const GitCommitSchema = z.object({
  message: z.string().describe("Commit message"),
});

const GitPushSchema = z.object({});

const DeployThemeSchema = z.object({
  environment: z.enum(["development", "production"]).default("development").describe("Deployment target"),
});

export function registerGitTools(server: Server, themeClient: LocalThemeClient) {
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    try {
      switch (name) {
        case "git_status": {
          const status = await themeClient.gitStatus();

          if (!status.trim()) {
            return {
              content: [
                {
                  type: "text",
                  text: "✨ Working directory clean - no changes to commit",
                } as TextContent,
              ],
            };
          }

          return {
            content: [
              {
                type: "text",
                text: `📝 Git status:\n${status}`,
              } as TextContent,
            ],
          };
        }

        case "git_commit": {
          const parsed = GitCommitSchema.parse(args);

          await themeClient.gitCommit(parsed.message);

          return {
            content: [
              {
                type: "text",
                text: `✅ Committed changes: "${parsed.message}"`,
              } as TextContent,
            ],
          };
        }

        case "git_push": {
          await themeClient.gitPush();

          return {
            content: [
              {
                type: "text",
                text: "✅ Pushed changes to remote repository",
              } as TextContent,
            ],
          };
        }

        case "deploy_theme": {
          const parsed = DeployThemeSchema.parse(args);

          const output = await themeClient.deployTheme(parsed.environment);

          return {
            content: [
              {
                type: "text",
                text: `🚀 Deploying to ${parsed.environment}...\n${output}`,
              } as TextContent,
            ],
          };
        }

        default:
          return null;
      }
    } catch (error) {
      if (["git_status", "git_commit", "git_push", "deploy_theme"].includes(name)) {
        return {
          content: [
            {
              type: "text",
              text: `❌ Error: ${error instanceof Error ? error.message : String(error)}`,
            } as ErrorContent,
          ],
          isError: true,
        };
      }
      return null;
    }
  });
}

