    try {
      const config = await fs.readFile(configPath, "utf-8");
      this.editableConfig = JSON.parse(config);
    } catch (error) {
      console.warn("No editable config found, allowing all fields");
      this.editableConfig = null;
    }
  }

  private isFieldEditable(file: string, fieldPath: string): boolean {
    // If no config, allow all (dangerous!)
    if (!this.editableConfig) return true;

    // Check if file is in editable list
    const fileConfig = this.editableConfig.editableFiles[file];
    if (!fileConfig) return false;

    // Check forbidden patterns
    for (const forbidden of this.editableConfig.forbiddenPatterns || []) {
      if (fieldPath.toLowerCase().includes(forbidden)) {
        return false;
      }
    }

    // Check if field matches any editable pattern
    for (const pattern of fileConfig.editableFields) {
      // Convert pattern to regex (e.g., "sections.*.settings.title" -> /sections\..*\.settings\.title/)
      const regexPattern = pattern
        .replace(/\./g, "\\.")
        .replace(/\*/g, ".*");

      if (new RegExp(`^${regexPattern}$`).test(fieldPath)) {
        return true;
      }
    }

    return false;
  }

