import fs from "fs/promises";
import path from "path";
import { exec } from "child_process";
import { promisify } from "util";

const execAsync = promisify(exec);

export interface ThemeCopyField {
  file: string;
  path: string;
  field: string;
  value: string;
  type: "text" | "html" | "json";
}

export interface ThemeSection {
  type: string;
  settings: Record<string, any>;
  blocks?: Record<string, any>;
}

export class LocalThemeClient {
  constructor(private themePath: string) {
    // Ensure path is absolute
    this.themePath = path.resolve(themePath);
  }

  // Validate theme directory
  async validateTheme(): Promise<boolean> {
    try {
      const stats = await fs.stat(this.themePath);
      if (!stats.isDirectory()) return false;

      // Check for required directories
      const requiredDirs = ["templates", "sections", "config", "locales"];
      for (const dir of requiredDirs) {
        try {
          await fs.stat(path.join(this.themePath, dir));
        } catch {
          console.warn(`Missing directory: ${dir}`);
        }
      }
      return true;
    } catch {
      return false;
    }
  }

  // Extract all copy from theme
  async extractAllCopy(): Promise<ThemeCopyField[]> {
    const copy: ThemeCopyField[] = [];

    // Extract from templates
    const templatesDir = path.join(this.themePath, "templates");
    const templateFiles = await fs.readdir(templatesDir);

    for (const file of templateFiles) {
      if (file.endsWith(".json")) {
        const content = await this.readJsonFile(path.join(templatesDir, file));
        const extracted = this.extractCopyFromJson(content, `templates/${file}`);
        copy.push(...extracted);
      }
    }

    // Extract from sections
    const sectionsDir = path.join(this.themePath, "sections");
    const sectionFiles = await fs.readdir(sectionsDir);

    for (const file of sectionFiles) {
      if (file.endsWith(".liquid")) {
        // Parse section schema for default content
        const content = await fs.readFile(path.join(sectionsDir, file), "utf-8");
        const schemaMatch = content.match(/{% schema %}([\s\S]*?){% endschema %}/);
        if (schemaMatch) {
          try {
            const schema = JSON.parse(schemaMatch[1]);
            const extracted = this.extractCopyFromSchema(schema, `sections/${file}`);
            copy.push(...extracted);
          } catch (e) {
            console.warn(`Failed to parse schema in ${file}`);
          }
        }
      }
    }

    // Extract from config/settings_data.json
    const settingsPath = path.join(this.themePath, "config", "settings_data.json");
    try {
      const settings = await this.readJsonFile(settingsPath);
      const extracted = this.extractCopyFromJson(settings, "config/settings_data.json");
      copy.push(...extracted);
    } catch {
      console.warn("No settings_data.json found");
    }

    return copy;
  }

  // Extract copy from JSON structure
  private extractCopyFromJson(obj: any, filePath: string, currentPath: string = ""): ThemeCopyField[] {
    const copy: ThemeCopyField[] = [];
    const textFields = ["text", "title", "heading", "subtitle", "description", "label", "content", "word_text", "button_text", "cta_text"];

    for (const [key, value] of Object.entries(obj)) {
      const fullPath = currentPath ? `${currentPath}.${key}` : key;

      if (typeof value === "string" && textFields.some(field => key.includes(field))) {
        copy.push({
          file: filePath,
          path: fullPath,
          field: key,
          value: value,
          type: "text",
        });
      } else if (typeof value === "object" && value !== null) {
        copy.push(...this.extractCopyFromJson(value, filePath, fullPath));
      }
    }

    return copy;
  }

  // Extract copy from section schema
  private extractCopyFromSchema(schema: any, filePath: string): ThemeCopyField[] {
    const copy: ThemeCopyField[] = [];

    // Extract from settings defaults
    if (schema.settings) {
      for (const setting of schema.settings) {
        if (setting.default && typeof setting.default === "string") {
          copy.push({
            file: filePath,
            path: `settings.${setting.id}`,
            field: setting.id,
            value: setting.default,
            type: "text",
          });
        }
      }
    }

    // Extract from blocks
    if (schema.blocks) {
      for (const block of schema.blocks) {
        if (block.settings) {
          for (const setting of block.settings) {
            if (setting.default && typeof setting.default === "string") {
              copy.push({
                file: filePath,
                path: `blocks.${block.type}.${setting.id}`,
                field: setting.id,
                value: setting.default,
                type: "text",
              });
            }
          }
        }
      }
    }

    return copy;
  }

  // Update a specific copy field
  async updateCopyField(file: string, jsonPath: string, newValue: string): Promise<void> {
    const fullPath = path.join(this.themePath, file);
    const content = await this.readJsonFile(fullPath);

    // Navigate to the field using the path
    const pathParts = jsonPath.split(".");
    let current = content;

    for (let i = 0; i < pathParts.length - 1; i++) {
      if (!(pathParts[i] in current)) {
        throw new Error(`Path ${jsonPath} not found in ${file}`);
      }
      current = current[pathParts[i]];
    }

    const lastKey = pathParts[pathParts.length - 1];
    if (!(lastKey in current)) {
      throw new Error(`Field ${lastKey} not found at path ${jsonPath}`);
    }

    // Update the value
    current[lastKey] = newValue;

    // Write back to file
    await this.writeJsonFile(fullPath, content);
  }

  // Bulk find/replace
  async bulkReplaceCopy(search: string, replace: string): Promise<number> {
    let count = 0;
    const allCopy = await this.extractAllCopy();

    for (const field of allCopy) {
      if (field.value.includes(search)) {
        const newValue = field.value.replace(new RegExp(search, "g"), replace);
        await this.updateCopyField(field.file, field.path, newValue);
        count++;
      }
    }

    return count;
  }

  // Git operations
  async gitStatus(): Promise<string> {
    const { stdout } = await execAsync("git status --short", { cwd: this.themePath });
    return stdout;
  }

  async gitCommit(message: string): Promise<void> {
    await execAsync("git add -A", { cwd: this.themePath });
    await execAsync(`git commit -m "${message}"`, { cwd: this.themePath });
  }

  async gitPush(): Promise<void> {
    await execAsync("git push", { cwd: this.themePath });
  }

  // Deploy to Shopify
  async deployTheme(environment: "development" | "production" = "development"): Promise<string> {
    const flag = environment === "development" ? "--development" : "";
    const { stdout } = await execAsync(`shopify theme push ${flag}`, { cwd: this.themePath });
    return stdout;
  }

  // Helper methods
  private async readJsonFile(filePath: string): Promise<any> {
    const content = await fs.readFile(filePath, "utf-8");
    // Remove Shopify's auto-generated comment header
    const jsonContent = content.replace(/\/\*[\s\S]*?\*\//g, "");
    return JSON.parse(jsonContent);
  }

  private async writeJsonFile(filePath: string, content: any): Promise<void> {
    // Check if file had the auto-generated header
    const originalContent = await fs.readFile(filePath, "utf-8");
    const headerMatch = originalContent.match(/\/\*[\s\S]*?\*\//);

    let output = JSON.stringify(content, null, 2);

    // Preserve the header if it existed
    if (headerMatch) {
      output = headerMatch[0] + "\n" + output;
    }

    await fs.writeFile(filePath, output, "utf-8");
  }

  // List all templates
  async listTemplates(): Promise<string[]> {
    const templatesDir = path.join(this.themePath, "templates");
    const files = await fs.readdir(templatesDir);
    return files.filter(f => f.endsWith(".json") || f.endsWith(".liquid"));
  }

  // Create a new template
  async createTemplate(name: string, sections: any[]): Promise<void> {
    const templatePath = path.join(this.themePath, "templates", `${name}.json`);
    const template = {
      sections: {},
      order: [],
    };

    // Add sections
    for (const section of sections) {
      const sectionId = `${section.type}_${Math.random().toString(36).substr(2, 6)}`;
      template.sections[sectionId] = section;
      template.order.push(sectionId);
    }

    await this.writeJsonFile(templatePath, template);
  }
}

