#!/usr/bin/env node

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { registerLocalCopyTools } from "./tools/localCopyTools.js";
import { registerLocalTemplateTools } from "./tools/localTemplateTools.js";
import { registerGitTools } from "./tools/gitTools.js";
import { LocalThemeClient } from "./lib/local-theme-client.js";
import dotenv from "dotenv";
import path from "path";

// Load environment variables
dotenv.config();

// Get theme path from environment or command line
const themePath = process.env.SHOPIFY_THEME_PATH || process.argv[2];

if (!themePath) {
  console.error("Error: Theme path required. Set SHOPIFY_THEME_PATH env var or pass as argument");
  console.error("Usage: shopify-liquid-mcp [theme-path]");
  process.exit(1);
}

// Initialize local theme client
const themeClient = new LocalThemeClient(themePath);

// Validate theme directory
const isValid = await themeClient.validateTheme();
if (!isValid) {
  console.error(`Error: Invalid theme directory at ${themePath}`);
  console.error("Make sure it contains templates/, sections/, config/, and locales/ directories");
  process.exit(1);
}

// Create MCP server
const server = new Server(
  {
    name: "shopify-liquid-mcp",
    version: "0.1.0",
  },
  {
    capabilities: {
      tools: {},
    },
  }
);

// Register tool handlers
registerLocalCopyTools(server, themeClient);
registerLocalTemplateTools(server, themeClient);
registerGitTools(server, themeClient);

// Handle tool listing
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      // Copy management tools
      {
        name: "get_page_copy",
        description: "Extract copy content from a Shopify page",
        inputSchema: {
          type: "object",
          properties: {
            page_id: {
              type: "string",
              description: "The ID of the page to extract copy from",
            },
          },
          required: ["page_id"],
        },
      },
      {
        name: "update_copy_field",
        description: "Update a specific text field on a page",
        inputSchema: {
          type: "object",
          properties: {
            page_id: {
              type: "string",
              description: "The ID of the page to update",
            },
            field: {
              type: "string",
              description: "The field to update (e.g., 'title', 'content', 'meta_description')",
            },
            content: {
              type: "string",
              description: "The new content for the field",
            },
          },
          required: ["page_id", "field", "content"],
        },
      },
      {
        name: "list_editable_pages",
        description: "List all pages available for editing",
        inputSchema: {
          type: "object",
          properties: {},
        },
      },
      // Page management tools
      {
        name: "create_page",
        description: "Create a new Shopify page",
        inputSchema: {
          type: "object",
          properties: {
            title: {
              type: "string",
              description: "The title of the new page",
            },
            content: {
              type: "string",
              description: "The HTML content of the page",
            },
            template_suffix: {
              type: "string",
              description: "Optional template suffix to use",
            },
          },
          required: ["title", "content"],
        },
      },
    ],
  };
});

// Start the server
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Shopify Liquid MCP Server started");
}

main().catch((error) => {
  console.error("Server error:", error);
  process.exit(1);
});
